const _ = require('lodash');

const CONSOLE = require('./console');

const EVENT = {
    /**
     * @memberof BXUI.EVENT
     */
     "addAllEventListenerWithOPTS": _addAllEventListenerWithOPTS,
    /**
     * @memberof BXUI.EVENT
     */
    "addCustomEvent": _addCustomEvent,
    /**
     * @memberof BXUI.EVENT
     */
    "hooks": _hooks,
    /**
     * @memberof BXUI.EVENT
     */
    "getEventNames": _getEventNames,
    /**
     * @memberof BXUI.EVENT
     */
    "isEventName": _isEventName
};


/**
 *
 * 커스텀 엘리먼트 이벤트 추가 함수
 *
 * @param {object} $elem - 엘리먼트 객체
 * @param {object} opts - 커스텀 엘리먼트 옵션
 *
 * @return {object} BXUI.Event 객체
 *
 */
function _addAllEventListenerWithOPTS($elem = null, opts = {}){

    if (_.isNull($elem)){
        CONSOLE.prop.throw('BXUI.Event.addAllEventListenerWithOPTS', '$elem', 'type');
    }

    if (!_.isFunction($elem.get) || !_.isElement($elem.get(0))){
        CONSOLE.prop.throw('BXUI.Event.addAllEventListenerWithOPTS', '$elem', 'type');
    }

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw('BXUI.Event.addAllEventListenerWithOPTS', 'opts', 'type');
    }


    _.map(opts, (v, k) => {

        if (k === 'attr'){

            _.map(opts.attr, (vv, kk) => {

                kk = replaceEventName(kk);

                if (_.trim(kk).length){

                    let instance = this;

                    _.isFunction(vv) && $elem.on(kk, function(e){
                        vv.bind(_.assign(this, instance), Array.prototype.slice.call(arguments, 1))();
                    });
                }
            });
        }
        else{

            k = replaceEventName(k);

            if (_.trim(k).length){
                _addCustomEvent(k);
            }
        }
    });


    // bx 이벤트명을 변환시키는 함수
    function replaceEventName(k = ''){

        let ret = '';

        let mt = k.match(/^bx-[a-z]+/);

        if (mt && mt[0]){
            ret = k.replace('bx-', '').toLowerCase();
        }

        return ret;
    }

    return this;
}

/**
 *
 * 커스텀 이벤트 추가 함수
 *
 * @param {String} evtName - 이벤트명
 *
 * @return {object} BXUI.Event 객체
 *
 */
function _addCustomEvent(evtName = ''){

    if (!_.isString(evtName) || !_.trim(evtName).length){
        CONSOLE.prop.throw('BXUI.Event.addCustomEvent', 'evtName', 'all');
    }

    _hooks(evtName, {

        add: function(o){

            let handler = o.handler;

            o.handler = function(e){
                return handler.apply(this, Array.prototype.slice.call(arguments, 1));
            };
        }
    });

    return this;
}

/**
 *
 * 커스텀 이벤트 추가 함수
 *
 * @param {String} evtName - 이벤트명
 * @param {object} hooks - hooking 객체
 *
 * @return {object} BXUI.Event 객체
 *
 * http://d2.naver.com/helloworld/1855209
 */
function _hooks(evtName = '', hooks = {}){

    if (!_.isString(evtName) || !_.trim(evtName).length){
        CONSOLE.prop.throw('BXUI.Event.hooks', 'evtName', 'all');
    }

    if (!_.isPlainObject(hooks)){
        CONSOLE.prop.throw('BXUI.Event.hooks', 'hooks', 'type');
    }

    $.event.special[evtName] = hooks;

    return this;
}

/**
 *
 * 엘리먼트가 가진 이벤트 집합을 반환한다.
 *
 * @param {object} $elem - 엘리먼트 객체
 *
 * @return {object} BXUI.Event 객체
 *
 * http://d2.naver.com/helloworld/1855209
 */
function _getEventNames($elem = null){

    if (_.isNull($elem)){
        CONSOLE.prop.throw('BXUI.Event.getEventNames', '$elem', 'type');
    }

    if (!_.isFunction($elem.get) || !_.isElement($elem.get(0))){
        CONSOLE.prop.throw('BXUI.Event.getEventNames', '$elem', 'type');
    }

    let elem = $elem.get(0);
    let ret = [];

    for (let k in elem){

        let mt = k.match(/^on/);

        if (mt && mt[0]){
            ret.push(k);
        }
    }

    return ret;
}

/**
 *
 * 전달받은 엘리먼트의 이벤트 유 / 무 를 반환한다.
 *
 * @param {String} evtName - 이벤트명
 *
 * @return {object} BXUI.Event 객체
 *
 */
function _isEventName($elem = null, evtName = ''){

    if (_.isNull($elem)){
        CONSOLE.prop.throw('BXUI.Event.isEventName', '$elem', 'type');
    }

    if (!_.isFunction($elem.get) || !_.isElement($elem.get(0))){
        CONSOLE.prop.throw('BXUI.Event.isEventName', '$elem', 'type');
    }

    if (!_.isString(evtName) || !_.trim(evtName).length){
        CONSOLE.prop.throw('BXUI.Event.isEventName', 'evtName', 'all');
    }

    let evtNames = _getEventNames($elem);

    return evtNames.indexOf(evtName) > -1 ? true : false;
}




module.exports = EVENT;